reference_solution:
def find_palindromes(words):
    result = []
    for word in words:
        lower = word.lower()
        if lower == lower[::-1]:
            result.append(word)
    return result

unit_tests:
import unittest

class TestSolution(unittest.TestCase):
    def test_basic_palindromes(self):
        self.assertEqual(find_palindromes(["racecar", "hello", "madam"]), ["racecar", "madam"])

    def test_mixed_case(self):
        self.assertEqual(find_palindromes(["Kayak", "Python", "Level"]), ["Kayak", "Level"])

    def test_no_palindromes(self):
        self.assertEqual(find_palindromes(["hello", "world"]), [])

    def test_hidden_empty_list(self):
        self.assertEqual(find_palindromes([]), [])

    def test_hidden_single_characters(self):
        self.assertEqual(find_palindromes(["a", "b"]), ["a", "b"])

    def test_hidden_all_palindromes(self):
        self.assertEqual(find_palindromes(["mom", "dad", "sis"]), ["mom", "dad", "sis"])

    def test_hidden_two_letter_words(self):
        self.assertEqual(find_palindromes(["aa", "ab", "bb"]), ["aa", "bb"])

    def test_hidden_empty_string(self):
        self.assertEqual(find_palindromes([""]), [""])

    def test_hidden_preserve_original_case(self):
        self.assertEqual(find_palindromes(["RaceCar", "Noon", "Test"]), ["RaceCar", "Noon"])

if __name__ == '__main__':
    unittest.main()
